package fate.org.apache.accumulo.fate.zookeeper;

public class Retry { private static final Logger log = LoggerFactory . getLogger ( Retry . class ) ; private long maxRetries , maxWait , waitIncrement ; private long retriesDone , currentWait ; public Retry ( long maxRetries , long startWait , long waitIncrement , long maxWait ) { this . maxRetries = maxRetries ; this . maxWait = maxWait ; this . waitIncrement = waitIncrement ; this . retriesDone = 0l ; this . currentWait = startWait ; } long getMaxRetries ( ) { return maxRetries ; } long getCurrentWait ( ) { return currentWait ; } long getWaitIncrement ( ) { return waitIncrement ; } long getMaxWait ( ) { return maxWait ; } void setMaxRetries ( long maxRetries ) { this . maxRetries = maxRetries ; } void setStartWait ( long startWait ) { this . currentWait = startWait ; } void setWaitIncrement ( long waitIncrement ) { this . waitIncrement = waitIncrement ; } void setMaxWait ( long maxWait ) { this . maxWait = maxWait ; } public boolean canRetry ( ) { return retriesDone < maxRetries ; } public void useRetry ( ) { if ( ! canRetry ( ) ) { throw new IllegalStateException ( "No retries left" ) ; } retriesDone ++ ; } public boolean hasRetried ( ) { return retriesDone > 0 ; } public long retriesCompleted ( ) { return retriesDone ; } public void waitForNextAttempt ( ) throws InterruptedException { log . debug ( "Sleeping for " + currentWait + "ms before retrying operation" ) ; sleep ( currentWait ) ; currentWait = Math . min ( maxWait , currentWait + waitIncrement ) ; } protected void sleep ( long wait ) throws InterruptedException { Thread . sleep ( wait ) ; } }